package com.vidaysalud.veterinaria.pagoservicio.model;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDateTime;@Entity @Table(name="pago",uniqueConstraints=@UniqueConstraint(name="uq_pago_consulta",columnNames="id_consulta")) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Pago{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)@Column(name="id_pago")private Integer idPago;@Column(name="id_consulta",nullable=false,unique=true)private Integer idConsulta;@Column(nullable=false,precision=10,scale=2)private BigDecimal monto;@Enumerated(EnumType.STRING)@Column(name="metodo_pago",nullable=false)private MetodoPago metodoPago;@Enumerated(EnumType.STRING)@Column(nullable=false)private EstadoPago estado;@Column(name="fecha_pago")private LocalDateTime fechaPago;@Column(length=100)private String referencia;@PrePersist void pre(){if(estado==null)estado=EstadoPago.PENDIENTE;if(estado==EstadoPago.PAGADO&&fechaPago==null)fechaPago=LocalDateTime.now();}}